#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF INT_MAX
#define MIN(a, b) ((a) < (b) ? (a) : (b))
typedef struct Edge {
    int to;
    int weight;
    struct Edge* next;
} Edge;
typedef struct Graph {
    int numVertices;
    Edge** adjLists;
} Graph;
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->adjLists = (Edge**) malloc(numVertices * sizeof(Edge*));
    for (int i = 0; i < numVertices; i++) {
        graph->adjLists[i] = NULL;
    }
    return graph;
}
void addEdge(Graph* graph, int src, int dest, int weight) {
    Edge* newNode = (Edge*) malloc(sizeof(Edge));
    newNode->to = dest;
    newNode->weight = weight;
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;
}
void dijkstra(Graph* graph, int src) {
    int* distances = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        distances[i] = INF;
    }
    distances[src] = 0;
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < graph->numVertices - 1; i++) {
        int minDistance = INF;
        int minIndex = -1;
        for (int j = 0; j < graph->numVertices; j++) {
            if (!visited[j] && distances[j] < minDistance) {
                minDistance = distances[j];
                minIndex = j;
            }
        }
        visited[minIndex] = 1;
        Edge* temp = graph->adjLists[minIndex];
        while (temp) {
            if (!visited[temp->to] && distances[minIndex] + temp->weight < distances[temp->to]) {
                distances[temp->to] = distances[minIndex] + temp->weight;
            }
            temp = temp->next;
        }
    }
    for (int i = 0; i < graph->numVertices; i++) {
        printf("%d ", distances[i]);
    }
    printf("\n");
    free(distances);
    free(visited);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, X, M, S;
        scanf("%d %d %d %d %d", &N, &K, &X, &M, &S);
        Graph* graph = createGraph(N);
        for (int i = 0; i < K; i++) {
            for (int j = i + 1; j < K; j++) {
                addEdge(graph, i, j, X);
                addEdge(graph, j, i, X);
            }
        }
        for (int i = 0; i < M; i++) {
            int a, b, c;
            scanf("%d %d %d", &a, &b, &c);
            addEdge(graph, a - 1, b - 1, c);
            addEdge(graph, b - 1, a - 1, c);
        }
        dijkstra(graph, S - 1);
        for (int i = 0; i < N; i++) {
            Edge* temp = graph->adjLists[i];
            while (temp) {
                Edge* next = temp->next;
                free(temp);
                temp = next;
            }
        }
        free(graph->adjLists);
        free(graph);
    }
    return 0;
}

