#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;
typedef long long ll;
const ll INF = 1e18;
void dijkstra(vector<vector<pair<int, int>>> &graph, int src, vector<ll> &distances) {
    priority_queue<pair<ll, int>, vector<pair<ll, int>>, greater<pair<ll, int>>> pq;
    pq.push({0, src});
    while (!pq.empty()) {
        ll currDist = pq.top().first;
        int currNode = pq.top().second;
        pq.pop();
        if (currDist > distances[currNode]) continue;
        for (auto &neighbor : graph[currNode]) {
            ll newDist = currDist + neighbor.second;
            if (newDist < distances[neighbor.first]) {
                distances[neighbor.first] = newDist;
                pq.push({newDist, neighbor.first});
            }
        }
    }
}
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N, K, X, M, S;
        cin >> N >> K >> X >> M >> S;
        vector<vector<pair<int, int>>> graph(N);
        for (int i = 0; i < K; i++) {
            for (int j = i + 1; j < K; j++) {
                graph[i].push_back({j, X});
                graph[j].push_back({i, X});
            }
        }
        for (int i = 0; i < M; i++) {
