import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.ArrayList;
import java.util.List;
public class Main {
    static class Pair implements Comparable<Pair> {
        int node;
        long distance;
        Pair(int node, long distance) {
            this.node = node;
            this.distance = distance;
        }
        @Override
        public int compareTo(Pair other) {
            return Long.compare(this.distance, other.distance);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            int X = scanner.nextInt();
            int M = scanner.nextInt();
            int S = scanner.nextInt();
            List<List<Pair>> graph = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                graph.add(new ArrayList<>());
            }
            for (int i = 0; i < K; i++) {
                for (int j = i + 1; j < K; j++) {
                    graph.get(i).add(new Pair(j, X));
                    graph.get(j).add(new Pair(i, X));
                }
            }
            for (int i = 0; i < M; i++) {
                int a = scanner.nextInt() - 1;
                int b = scanner.nextInt() - 1;
                int c = scanner.nextInt();
                graph.get(a).add(new Pair(b, c));
                graph.get(b).add(new Pair(a, c));
            }
            long[] distances = new long[N];
            for (int i = 0; i < N; i++) {
                distances[i] = Long.MAX_VALUE;
            }
            distances[S - 1] = 0;
            PriorityQueue<Pair> pq = new PriorityQueue<>();
            pq.add(new Pair(S - 1, 0));
            while (!pq.isEmpty()) {
                Pair curr = pq.poll();
                if (curr.distance > distances[curr.node]) continue;
                for (Pair neighbor : graph.get(curr.node)) {
                    long newDistance = curr.distance + neighbor.distance;
                    if (newDistance < distances[neighbor.node]) {
                        distances[neighbor.node] = newDistance;
                        pq.add(new Pair(neighbor.node, newDistance));
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                System.out.print(distances[i] + " ");
            }
            System.out.println();
        }
    }
}

